var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 아저씨들 글러먹었네. 남의 발명품을 면전에서 무시하고 말이야.","JPN":"あのおじさんたちってダメだね。人の発明品を面と向かって見くびってさ。","ENG":"Those guys are hopeless. Dismissing my invention right to my face.","TWN":"那群叔叔真白目，竟然當著發明者的面說他發明的東西不好。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"예전 생각이 나더군. 처음 얘길 꺼냈을 땐 그대도 비슷한 반응이었지.","JPN":"昔のことを思い出すな。初めて話を聞いたそなたも似たような反応をしていた。","ENG":"It reminded me of the first time I told you about it. Your reaction wasn't so different.","TWN":"讓我想起我第一次跟你說這件事的時候，你的反應也跟他們差不多。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이게 다 사부가 네이밍 센스가 구려서 그래.","JPN":"師匠のネーミングセンスがダサいからだよ。","ENG":"That's because your naming sense is awful, Master.","TWN":"還不是因為師父很不會取名字。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이 참에 장치 이름도 좀 더 그럴싸하고 과학적으로 바꿔버리자! 엔트로피, 양자역학, 이런 어려운 말 막 섞어서 말이야!","JPN":"これを機にさ、装置の名前ももうちょっとそれっぽくて科学的なやつに変えようよ！　エントロピーとか量子力学とか、難しい言葉も入れてさ！","ENG":"We should just rename the device to something cooler. Toss in words like \\"entropy\\" or \\"quantum mechanics\\" to make it sound cooler!","TWN":"不如趁這個機會，把裝置的名字改得更帥氣、更科學一點吧！像是混入熵、量子力學，這種很難的詞！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"알아듣기 쉬우면 되는 걸세. 구태여 어려운 표현을 쓸 이유는 없지 않은가.","JPN":"分かりやすければそれでいいのだ。あえて難しい表現を用いる必要はなかろう。","ENG":"Simple names are best. No need to dress it up with fancy words.","TWN":"重點是容易理解，沒必要用艱深的詞彙吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"내가 답답해서 그런다. 사부처럼 엄청 똑똑한 사람이 무시당하는 거 싫단 말야.","JPN":"見ていられないんだよ。師匠みたいに頭いい人が見下されるの。","ENG":"It just annoys me. I hate seeing someone as smart as you brushed off like that.","TWN":"我不能接受！我不喜歡像師父這麼聰明的人被看不起。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"누가 인정하고 말고는 상관없네. 내가 원해서 시작한 일이니까.","JPN":"他人の評価などどうでもよい。自分が望んで始めた仕事ゆえ。","ENG":"Doesn't matter if others approve. I started this for my own reasons.","TWN":"別人認不認可都無所謂。這是我自己想做的事。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이 낡은 격납고를 본부로 쓰는 것도 문제야. 누가 이런 볼품없는 연구소에 지원하겠어?","JPN":"だいたいさ、このボロっちい格納庫を本部にした時点でアウトだって。こんなみすぼらしい研究所見たら、誰も支援したがらないよ。","ENG":"This rundown hangar we call HQ doesn't help either. Who'd wanna sign up for a shabby lab like this?","TWN":"用這個破舊的機庫當總部也是個問題，誰會想加入這麼寒酸的研究室？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"간판을 다는 것 정돈 고려해봐도 괜찮겠지.","JPN":"看板をつけることぐらいは検討しよう。","ENG":"Maybe I'll hang a proper signboard someday.","TWN":"是可以考慮掛個招牌。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이터니움을 구하느라 주머니 사정이 빠듯하여, 지금으로선 이게 최선일세.","JPN":"エタニウムの調達に予算を使いすぎて、今はこれが精一杯だ。","ENG":"But for now, all the Eternium drained the coffers. This is the best we can do.","TWN":"因為買永恆之金，手頭有點緊，現在也只能這樣。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 이동요새 만드는 데 전재산을 박지만 않았어도 됐을걸?","JPN":"あの移動要塞を作るのに全財産つぎ込んだからじゃない。","ENG":"We wouldn't be broke if you hadn't poured everything into that moving fortress.","TWN":"誰叫你要把全部家當都拿去蓋那個移動要塞。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이동요새는 낭만이지. 집이 움직이면 먹비를 피할 수도 있고 좋지 않나.","JPN":"移動要塞には浪漫がある。家が動けば墨雨を避けることもできるし、よいではないか。","ENG":"It's romantic, isn't it? A house that moves means we can dodge the Ink Rain.","TWN":"移動要塞是我的夢想。家會動的話，就可以躲避墨雨，不是很好嗎。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"문제는 예산 부족으로 아직 완성도 못했다는 거지만.","JPN":"問題は、予算不足でまだ完成すらしてないってことだけどね。","ENG":"Yeah, well, the problem is that it's still unfinished because we ran out of funds.","TWN":"問題是預算不足，還沒完成。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"역시 대포는 달지 말았어야 했나?","JPN":"やはり大砲はつけない方がよかっただろうか。","ENG":"Maybe I shouldn't have added the cannon.","TWN":"果然不該裝大砲嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"말했잖아. 우리한테 필요한 건 대포 달린 움직이는 집이 아니라 일꾼이라고.","JPN":"だから言ったじゃん。私たちに必要なのは、大砲のついた動く家じゃなくて人手だって。","ENG":"Told you. We don't need a house with a cannon. We need more workers.","TWN":"我說過啦。我們需要的不是一間有大砲、會移動的房子，而是工人。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>과거로 가기 위한 장치</color>도 도와줄 사람만 있었으면 만드는 데 꼬박 두 달이 걸리진 않았을 걸?","JPN":"<color=#ffd34c>過去へ向かうための装置</color>も、人手さえあれば作るのに2か月もかかったりしなかったよ。","ENG":"If we'd had a bigger team, that <color=#ffd34c>device to the past</color> wouldn't have taken two months to build.","TWN":"如果有人幫忙，<color=#ffd34c>回到過去的裝置</color>也不會整整花兩個月才完成吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"당장 이번 설치 작업도 그 아저씨들 아니었으면 하루가 아니라 3주가 걸렸을 테고.","JPN":"今回の設置作業だって、あのおじさんたちがいなかったら1日どころか3週間ぐらいかかってた。","ENG":"Even this last installation job. Without those delivery guys, it would've taken us three weeks instead of a day.","TWN":"就連這次的安裝工作，如果沒有那群叔叔幫忙，我們也得花上三個星期。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이게 다 사람 잘 부리는 제자를 둔 덕분 아니겠나.","JPN":"人の扱いに長けた弟子のおかげだな。","ENG":"All thanks to my resourceful apprentice.","TWN":"這都是因為我有一個很會用人的徒弟。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"방금 칭찬이 아니라 돌려 깐 거지?","JPN":"それって褒めてるんじゃなくて遠まわしにディスってない？","ENG":"Hey, that's not compliment. That's a backhanded jab, isn't it?","TWN":"那是在稱讚我，還是諷刺我？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"난 돌려 말하는 재주 같은 건 없다네.","JPN":"某に遠まわしに言う才能はない。","ENG":"I'm not clever enough for backhanded words.","TWN":"我沒有諷刺人的才能。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"반면 그댄 배우는 재주가 좋아서 워치에 금방 익숙해졌을 뿐만 아니라, 화술도, 요리 실력도 빼어나지.","JPN":"対してそなたは習得が早く、ウォッチにもすぐ慣れ、話術も料理の腕もずば抜けている。","ENG":"On the other hand, you're a quick learner. Good with the Watch, skilled at talking and cooking.","TWN":"反之，你學習能力很好，不只很快就習慣能量環，口才和廚藝也很出色。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"유능한 조수 덕에 난 내 일에만 몰두할 수 있으니, 항상 고맙게 생각하고 있어.","JPN":"有能な助手のおかげで、某は自分の仕事に集中できる。いつも有難く思っているのだ。","ENG":"Thanks to my capable assistant, I can focus on my work. I'm always grateful for that.","TWN":"因為有你這麼能幹的助手，我才能專心做我的事，我一直很感謝你。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 평소엔 하지도 않던 칭찬을 마구 해대고…","JPN":"ど、どうしちゃったの？　いつもはそんな褒め言葉言わないくせに。","ENG":"Whoa. Where's all this praise coming from? You never say this stuff…","TWN":"什，什麼？你從來不稱讚我的，今天怎麼…"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그런 의미에서 오늘 저녁은 계란찜이 좋겠는데.","JPN":"というわけで、今日の晩飯は茶碗蒸しがよいな。","ENG":"So tonight, steamed eggs would be nice.","TWN":"既然如此，今天晚上就吃蒸蛋吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"에휴, 알았으니까 밥 할 동안 사부는 잠이나 좀 자둬.","JPN":"はあ、分かったからご飯作ってる間、師匠はちょっと寝といて。","ENG":"*Sigh* While I'm cooking, you better get some sleep.","TWN":"唉，好啦。我去做飯，師父先去睡一覺吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};